import json
from beeai import LLMResponseEvent
from vex_sdk import VexMonitor

class GraniteFormatValidator(VexMonitor):
    def on_llm_response(self, event: LLMResponseEvent):
        if 'granite' in event.model_name.lower():
            try:
                parsed = json.loads(event.content)
                required_fields = ['tool_calls', 'reasoning']
                missing = [f for f in required_fields if f not in parsed]
                if missing:
                    self.alert(f"Granite format invalid: missing {missing}")
                    event.retry_with_prompt_fix()
            except json.JSONDecodeError:
                self.alert("Granite returned non-JSON response")
                event.force_structured_output()

agent.add_observer(GraniteFormatValidator())

