from pydantic import BaseModel, validator
from beeai import Tool
from vex_sdk import VexFix

class SafeCalculatorTool(Tool):
    class Input(BaseModel):
        expression: str

        @validator('expression')
        def safe_expression(cls, v):
            banned = ['delete', 'drop', 'exec', 'system', 'import']
            if any(word in v.lower() for word in banned):
                raise ValueError('Unsafe expression')
            if len(v) > 100:
                raise ValueError('Expression too long')
            return v

    def execute(self, input: Input):
        # Sandboxed evaluation
        allowed = {'+': 1, '-': 1, '*': 1, '/': 1, 'sin': 1, 'cos': 1}
        return eval(input.expression, {"__builtins__": {}}, allowed)

agent.register_tool(SafeCalculatorTool())

import json
from typing import Any
from beeai import AgentState
from vex_sdk import VexFix

class SerializableState(VexFix):
    def custom_encoder(self, obj: Any) -> Any:
        if callable(obj):
            return f"<function:{obj.__name__}>"
        if hasattr(obj, '__dict__'):
            return {k: v for k, v in obj.__dict__.items() 
                   if not k.startswith('_')}
        return str(obj)

    def apply_fix(self, state: AgentState):
        serializable = json.dumps(state.dict(), default=self.custom_encoder)
        state.save_to_redis(serializable)
        self.log(f"Persisted {len(serializable)} bytes of state")

agent.add_auto_fix(SerializableState())
